from typing import List
from pydantic import BaseModel, constr


class CeilingTypeBase(BaseModel):
    name: constr(min_length=1, max_length=50)
    description: constr(min_length=1, max_length=255)


class CeilingTypeCreateDto(CeilingTypeBase):
    pass


class CeilingTypeUpdateDto(CeilingTypeBase):
    pass


class CeilingTypeReadDto(CeilingTypeBase):
    id: uuid.UUID

    class Config:
        orm_mode = True


class CeilingTypeInDB(CeilingTypeBase):
    id: uuid.UUID


class CeilingTypeBizLogic:
    async def create_ceiling_type(self, obj: CeilingTypeCreateDto) -> CeilingTypeReadDto:
        obj.verify()
        orm_obj = CeilingTypeInDB(**obj.dict())
        ceiling_type = await postgresql_manager.create(CeilingType, orm_obj)
        return CeilingTypeReadDto.from_orm(ceiling_type)

    async def read_all_ceiling_types(self) -> List[CeilingTypeReadDto]:
        ceiling_types = await postgresql_manager.read_all(CeilingType)
        return [CeilingTypeReadDto.from_orm(ct) for ct in ceiling_types]

    async def read_ceiling_type(self, id: uuid.UUID) -> CeilingTypeReadDto:
        ceiling_type = await postgresql_manager.read(CeilingType, id)
        return CeilingTypeReadDto.from_orm(ceiling_type)

    async def update_ceiling_type(self, id: uuid.UUID, obj: CeilingTypeUpdateDto) -> CeilingTypeReadDto:
        obj.verify()
        updates = obj.dict(exclude_unset=True)
        ceiling_type = await postgresql_manager.update(CeilingType, id, updates)
        return CeilingTypeReadDto.from_orm(ceiling_type)

    async def delete_ceiling_type(self, id: uuid.UUID) -> CeilingTypeReadDto:
        ceiling_type = await postgresql_manager.delete(CeilingType, id)
        return CeilingTypeReadDto.from_orm(ceiling_type)

